#include<bits/stdc++.h>
using namespace std;
int n,p,a[5000001];
int main(){
    cin>>n>>p;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=n;i>=1;i--) a[i]=a[i]-a[i-1];
    for(int i=1;i<=p;i++){
        int x,y,z;
        cin>>x>>y>>z;
        a[x]+=z;
        a[y+1]-=z;
    }
    int minn=1e9;
    for(int i=1;i<=n;i++) a[i]=a[i]+a[i-1],minn=min(minn,a[i]);
    //for(int i=1;i<=n;i++) cout<<a[i]<<' ';
    cout<<minn;
    return 0;
}
